import * as PIXI from 'pixi.js';
import type { TimelineContext } from '../core/Timeline.js';
import type { PrecisionTimestamp } from '@psyforge/timing';

export interface StimulusOptions {
  duration?: number;
  position?: { x: number; y: number };
  size?: { width: number; height: number };
  opacity?: number;
  rotation?: number;
  anchor?: { x: number; y: number };
  zIndex?: number;
}

export abstract class BaseStimulus {
  protected app?: PIXI.Application;
  protected container?: PIXI.Container;
  protected displayObject?: PIXI.DisplayObject;
  protected options: StimulusOptions;
  protected onsetTime?: PrecisionTimestamp;
  protected offsetTime?: PrecisionTimestamp;
  private removeTimeout?: number;

  constructor(options: StimulusOptions = {}) {
    this.options = {
      position: { x: 0, y: 0 },
      opacity: 1,
      rotation: 0,
      anchor: { x: 0.5, y: 0.5 },
      zIndex: 0,
      ...options,
    };
  }

  abstract createDisplayObject(): Promise<PIXI.DisplayObject>;
  abstract getType(): string;

  async initialize(context: TimelineContext): Promise<void> {
    // Get or create PIXI application
    this.app = await this.getOrCreateApp();

    // Create the display object for this stimulus
    this.displayObject = await this.createDisplayObject();

    // Apply common properties
    if (this.displayObject) {
      this.displayObject.position.set(
        this.options.position!.x,
        this.options.position!.y
      );

      this.displayObject.alpha = this.options.opacity!;
      this.displayObject.rotation = this.options.rotation!;

      if (this.options.size) {
        this.displayObject.width = this.options.size.width;
        this.displayObject.height = this.options.size.height;
      }

      this.displayObject.zIndex = this.options.zIndex!;
    }
  }

  async present(context: TimelineContext): Promise<void> {
    if (!this.app || !this.displayObject) {
      throw new Error('Stimulus not initialized');
    }

    // Record onset time
    this.onsetTime = context.clock.now();

    // Add to stage
    this.app.stage.addChild(this.displayObject);

    // Schedule removal if duration is specified
    if (this.options.duration) {
      this.removeTimeout = window.setTimeout(() => {
        this.remove(context);
      }, this.options.duration);
    }
  }

  async remove(context: TimelineContext): Promise<void> {
    if (!this.app || !this.displayObject) {
      return;
    }

    // Clear timeout if exists
    if (this.removeTimeout) {
      clearTimeout(this.removeTimeout);
      this.removeTimeout = undefined;
    }

    // Record offset time
    this.offsetTime = context.clock.now();

    // Remove from stage
    this.app.stage.removeChild(this.displayObject);

    // Destroy display object to free memory
    this.displayObject.destroy();
    this.displayObject = undefined;
  }

  protected async getOrCreateApp(): Promise<PIXI.Application> {
    // Check if PIXI app already exists in the document
    const existingCanvas = document.getElementById('psyforge-canvas') as HTMLCanvasElement;

    if (existingCanvas && (window as any).__psyforgePixiApp) {
      return (window as any).__psyforgePixiApp;
    }

    // Create new PIXI application
    const app = new PIXI.Application();

    await app.init({
      width: window.innerWidth,
      height: window.innerHeight,
      antialias: true,
      resolution: window.devicePixelRatio || 1,
      autoDensity: true,
      backgroundColor: 0x000000,
      powerPreference: 'high-performance',
    });

    // Configure for psychology experiments
    app.stage.sortableChildren = true; // Enable z-index sorting

    // Add canvas to document
    app.canvas.id = 'psyforge-canvas';
    app.canvas.style.position = 'fixed';
    app.canvas.style.top = '0';
    app.canvas.style.left = '0';
    app.canvas.style.width = '100%';
    app.canvas.style.height = '100%';
    app.canvas.style.pointerEvents = 'none'; // Stimuli are not interactive by default

    document.body.appendChild(app.canvas);

    // Store globally for reuse
    (window as any).__psyforgePixiApp = app;

    // Handle window resize
    window.addEventListener('resize', () => {
      app.renderer.resize(window.innerWidth, window.innerHeight);
    });

    return app;
  }

  getOnsetTime(): PrecisionTimestamp | undefined {
    return this.onsetTime;
  }

  getOffsetTime(): PrecisionTimestamp | undefined {
    return this.offsetTime;
  }

  getDuration(): number | undefined {
    return this.options.duration;
  }

  getOptions(): StimulusOptions {
    return { ...this.options };
  }
}

