import * as PIXI from 'pixi.js';
import { BaseStimulus, type StimulusOptions } from './BaseStimulus.js';
import type { TimelineContext } from '../core/Timeline.js';
import { sanitizeUrl } from '../utils/security.js';

export interface ImageStimulusPixiOptions extends StimulusOptions {
  preload?: boolean;
  smoothing?: boolean;
  tint?: string;
  filters?: Array<'blur' | 'grayscale' | 'brightness' | 'contrast'>;
  filterValues?: {
    blur?: number;
    grayscale?: number;
    brightness?: number;
    contrast?: number;
  };
}

export class ImageStimulusPixi extends BaseStimulus {
  public readonly id: string;
  private imageUrl: string;
  private imageOptions: ImageStimulusPixiOptions;
  private sprite?: PIXI.Sprite;
  private texture?: PIXI.Texture;
  private loadPromise?: Promise<void>;

  constructor(
    id: string,
    url: string,
    options: ImageStimulusPixiOptions = {}
  ) {
    super(options);
    this.id = id;

    // Sanitize URL
    const sanitized = sanitizeUrl(url);
    if (!sanitized) {
      throw new Error('Invalid image URL provided');
    }
    this.imageUrl = sanitized;

    this.imageOptions = {
      preload: true,
      smoothing: true,
      ...options,
    };

    // Start preloading if requested
    if (this.imageOptions.preload) {
      this.preloadImage();
    }
  }

  getType(): string {
    return 'ImageStimulusPixi';
  }

  private async preloadImage(): Promise<void> {
    if (this.loadPromise) {
      return this.loadPromise;
    }

    this.loadPromise = new Promise((resolve, reject) => {
      PIXI.Assets.load(this.imageUrl)
        .then((texture) => {
          this.texture = texture;
          resolve();
        })
        .catch((error) => {
          console.error('Failed to preload image:', error);
          reject(error);
        });
    });

    return this.loadPromise;
  }

  async createDisplayObject(): Promise<PIXI.DisplayObject> {
    // Ensure image is loaded
    if (!this.texture) {
      await this.preloadImage();
    }

    if (!this.texture) {
      throw new Error('Failed to load image texture');
    }

    // Create sprite from texture
    this.sprite = new PIXI.Sprite(this.texture);

    // Set anchor for centering
    this.sprite.anchor.set(
      this.options.anchor!.x,
      this.options.anchor!.y
    );

    // Apply smoothing
    if (!this.imageOptions.smoothing) {
      this.sprite.texture.source.scaleMode = 'nearest';
    }

    // Apply tint if specified
    if (this.imageOptions.tint) {
      const tintValue = this.parseColor(this.imageOptions.tint);
      if (tintValue !== null) {
        this.sprite.tint = tintValue;
      }
    }

    // Apply filters if specified
    if (this.imageOptions.filters && this.imageOptions.filters.length > 0) {
      this.applyFilters();
    }

    return this.sprite;
  }

  private parseColor(color: string): number | null {
    // Convert CSS color to hex number
    if (color.startsWith('#')) {
      return parseInt(color.slice(1), 16);
    }

    // Common color names
    const colorMap: Record<string, number> = {
      white: 0xFFFFFF,
      black: 0x000000,
      red: 0xFF0000,
      green: 0x00FF00,
      blue: 0x0000FF,
      yellow: 0xFFFF00,
      cyan: 0x00FFFF,
      magenta: 0xFF00FF,
    };

    return colorMap[color.toLowerCase()] || null;
  }

  private applyFilters(): void {
    if (!this.sprite || !this.imageOptions.filters) return;

    const filters: PIXI.Filter[] = [];
    const values = this.imageOptions.filterValues || {};

    for (const filterType of this.imageOptions.filters) {
      switch (filterType) {
        case 'blur':
          const blurFilter = new PIXI.BlurFilter();
          blurFilter.blur = values.blur || 5;
          filters.push(blurFilter);
          break;

        case 'grayscale':
          const colorMatrix = new PIXI.ColorMatrixFilter();
          colorMatrix.desaturate();
          filters.push(colorMatrix);
          break;

        case 'brightness':
          const brightnessMatrix = new PIXI.ColorMatrixFilter();
          brightnessMatrix.brightness(values.brightness || 1.5, false);
          filters.push(brightnessMatrix);
          break;

        case 'contrast':
          const contrastMatrix = new PIXI.ColorMatrixFilter();
          contrastMatrix.contrast(values.contrast || 1.5, false);
          filters.push(contrastMatrix);
          break;
      }
    }

    this.sprite.filters = filters.length > 0 ? filters : null;
  }

  // Fluent API methods
  src(url: string): this {
    const sanitized = sanitizeUrl(url);
    if (!sanitized) {
      throw new Error('Invalid image URL provided');
    }
    this.imageUrl = sanitized;

    // Reset texture and load promise
    this.texture = undefined;
    this.loadPromise = undefined;

    if (this.imageOptions.preload) {
      this.preloadImage();
    }

    return this;
  }

  tint(color: string): this {
    this.imageOptions.tint = color;
    if (this.sprite) {
      const tintValue = this.parseColor(color);
      if (tintValue !== null) {
        this.sprite.tint = tintValue;
      }
    }
    return this;
  }

  blur(amount: number = 5): this {
    if (!this.imageOptions.filters) {
      this.imageOptions.filters = [];
    }
    if (!this.imageOptions.filters.includes('blur')) {
      this.imageOptions.filters.push('blur');
    }
    if (!this.imageOptions.filterValues) {
      this.imageOptions.filterValues = {};
    }
    this.imageOptions.filterValues.blur = amount;

    if (this.sprite) {
      this.applyFilters();
    }

    return this;
  }

  grayscale(): this {
    if (!this.imageOptions.filters) {
      this.imageOptions.filters = [];
    }
    if (!this.imageOptions.filters.includes('grayscale')) {
      this.imageOptions.filters.push('grayscale');
    }

    if (this.sprite) {
      this.applyFilters();
    }

    return this;
  }

  brightness(value: number): this {
    if (!this.imageOptions.filters) {
      this.imageOptions.filters = [];
    }
    if (!this.imageOptions.filters.includes('brightness')) {
      this.imageOptions.filters.push('brightness');
    }
    if (!this.imageOptions.filterValues) {
      this.imageOptions.filterValues = {};
    }
    this.imageOptions.filterValues.brightness = value;

    if (this.sprite) {
      this.applyFilters();
    }

    return this;
  }

  contrast(value: number): this {
    if (!this.imageOptions.filters) {
      this.imageOptions.filters = [];
    }
    if (!this.imageOptions.filters.includes('contrast')) {
      this.imageOptions.filters.push('contrast');
    }
    if (!this.imageOptions.filterValues) {
      this.imageOptions.filterValues = {};
    }
    this.imageOptions.filterValues.contrast = value;

    if (this.sprite) {
      this.applyFilters();
    }

    return this;
  }

  scale(x: number, y?: number): this {
    const scaleY = y !== undefined ? y : x;
    if (this.sprite) {
      this.sprite.scale.set(x, scaleY);
    }
    return this;
  }

  // Animation methods
  async scaleAnimation(
    fromScale: number,
    toScale: number,
    duration: number = 1000
  ): Promise<void> {
    if (!this.sprite) return;

    const startTime = performance.now();
    this.sprite.scale.set(fromScale);

    return new Promise((resolve) => {
      const animate = () => {
        const elapsed = performance.now() - startTime;
        const progress = Math.min(elapsed / duration, 1);

        if (this.sprite) {
          const currentScale = fromScale + (toScale - fromScale) * progress;
          this.sprite.scale.set(currentScale);
        }

        if (progress < 1) {
          requestAnimationFrame(animate);
        } else {
          resolve();
        }
      };
      animate();
    });
  }

  async rotationAnimation(
    fromAngle: number,
    toAngle: number,
    duration: number = 1000
  ): Promise<void> {
    if (!this.sprite) return;

    const startTime = performance.now();
    this.sprite.rotation = fromAngle * (Math.PI / 180);

    return new Promise((resolve) => {
      const animate = () => {
