import * as PIXI from 'pixi.js';
import { BaseStimulus, type StimulusOptions } from './BaseStimulus.js';
import type { TimelineContext } from '../core/Timeline.js';
import { sanitizeColorValue } from '../utils/security.js';

export type ShapeType = 'rectangle' | 'circle' | 'ellipse' | 'polygon' | 'star' | 'rounded-rectangle';

export interface ShapeStimulusPixiOptions extends StimulusOptions {
  fillColor?: string;
  strokeColor?: string;
  strokeWidth?: number;
  strokeAlignment?: number; // 0 = inner, 0.5 = center, 1 = outer
  cornerRadius?: number; // For rounded rectangles
  sides?: number; // For polygons
  innerRadius?: number; // For stars
  outerRadius?: number; // For stars
  points?: Array<{ x: number; y: number }>; // For custom polygons
}

export class ShapeStimulusPixi extends BaseStimulus {
  public readonly id: string;
  private shapeType: ShapeType;
  private shapeOptions: ShapeStimulusPixiOptions;
  private graphics?: PIXI.Graphics;

  constructor(
    id: string,
    type: ShapeType,
    options: ShapeStimulusPixiOptions = {}
  ) {
    super(options);
    this.id = id;
    this.shapeType = type;
    this.shapeOptions = {
      fillColor: '#FFFFFF',
      strokeWidth: 0,
      strokeAlignment: 0.5,
      cornerRadius: 0,
      sides: 6,
      innerRadius: 50,
      outerRadius: 100,
      ...options,
    };
  }

  getType(): string {
    return 'ShapeStimulusPixi';
  }

  async createDisplayObject(): Promise<PIXI.DisplayObject> {
    this.graphics = new PIXI.Graphics();

    // Set up fill
    const fillColor = this.parseColor(this.shapeOptions.fillColor);
    if (fillColor !== null) {
      this.graphics.fill({ color: fillColor });
    }

    // Set up stroke
    if (this.shapeOptions.strokeWidth && this.shapeOptions.strokeWidth > 0) {
      const strokeColor = this.parseColor(this.shapeOptions.strokeColor || '#000000');
      if (strokeColor !== null) {
        this.graphics.stroke({
          width: this.shapeOptions.strokeWidth,
          color: strokeColor,
          alignment: this.shapeOptions.strokeAlignment!,
        });
      }
    }

    // Draw the shape based on type
    const width = this.options.size?.width || 100;
    const height = this.options.size?.height || 100;

    switch (this.shapeType) {
      case 'rectangle':
        this.graphics.rect(-width / 2, -height / 2, width, height);
        break;

      case 'rounded-rectangle':
        this.graphics.roundRect(
          -width / 2,
          -height / 2,
          width,
          height,
          this.shapeOptions.cornerRadius!
        );
        break;

      case 'circle':
        const radius = Math.min(width, height) / 2;
        this.graphics.circle(0, 0, radius);
        break;

      case 'ellipse':
        this.graphics.ellipse(0, 0, width / 2, height / 2);
        break;

      case 'polygon':
        this.drawPolygon(this.shapeOptions.sides!);
        break;

      case 'star':
        this.drawStar(
          this.shapeOptions.sides!,
          this.shapeOptions.innerRadius!,
          this.shapeOptions.outerRadius!
        );
        break;
    }

    // Set pivot for rotation around center
    this.graphics.pivot.set(0, 0);

    return this.graphics;
  }

  private parseColor(color?: string): number | null {
    if (!color) return null;

    const sanitized = sanitizeColorValue(color);
    if (!sanitized) return null;

    // Convert CSS color to hex number
    if (sanitized.startsWith('#')) {
      return parseInt(sanitized.slice(1), 16);
    }

    // RGB/RGBA parsing
    const rgbMatch = sanitized.match(/rgba?\((\d+),\s*(\d+),\s*(\d+)/);
    if (rgbMatch) {
      const r = parseInt(rgbMatch[1]);
      const g = parseInt(rgbMatch[2]);
      const b = parseInt(rgbMatch[3]);
      return (r << 16) + (g << 8) + b;
    }

    // Common color names
    const colorMap: Record<string, number> = {
      white: 0xFFFFFF,
      black: 0x000000,
      red: 0xFF0000,
      green: 0x00FF00,
      blue: 0x0000FF,
      yellow: 0xFFFF00,
      cyan: 0x00FFFF,
      magenta: 0xFF00FF,
      orange: 0xFFA500,
      purple: 0x800080,
      gray: 0x808080,
      grey: 0x808080,
    };

    return colorMap[sanitized.toLowerCase()] || null;
  }

  private drawPolygon(sides: number): void {
    if (!this.graphics) return;

    const radius = Math.min(
      this.options.size?.width || 100,
      this.options.size?.height || 100
    ) / 2;

    const points: number[] = [];
    for (let i = 0; i < sides; i++) {
      const angle = (i * 2 * Math.PI) / sides - Math.PI / 2;
      points.push(
        Math.cos(angle) * radius,
        Math.sin(angle) * radius
      );
    }

    this.graphics.poly(points);
  }

  private drawStar(points: number, innerRadius: number, outerRadius: number): void {
    if (!this.graphics) return;

    const step = Math.PI / points;
    const starPoints: number[] = [];

    for (let i = 0; i < points * 2; i++) {
      const radius = i % 2 === 0 ? outerRadius : innerRadius;
      const angle = i * step - Math.PI / 2;
      starPoints.push(
        Math.cos(angle) * radius,
        Math.sin(angle) * radius
      );
    }

    this.graphics.poly(starPoints);
  }

  // Fluent API methods
  fill(color: string): this {
    const sanitized = sanitizeColorValue(color);
    if (sanitized) {
      this.shapeOptions.fillColor = sanitized;
      if (this.graphics) {
        // Recreate the shape with new color
        this.createDisplayObject();
      }
    }
    return this;
  }

  stroke(color: string, width: number, alignment: number = 0.5): this {
    const sanitized = sanitizeColorValue(color);
    if (sanitized) {
      this.shapeOptions.strokeColor = sanitized;
      this.shapeOptions.strokeWidth = width;
      this.shapeOptions.strokeAlignment = alignment;
      if (this.graphics) {
        // Recreate the shape with new stroke
        this.createDisplayObject();
      }
    }
    return this;
  }

  radius(value: number): this {
    if (this.shapeType === 'circle') {
      this.options.size = { width: value * 2, height: value * 2 };
    }
    return this;
  }

  corners(radius: number): this {
    if (this.shapeType === 'rounded-rectangle') {
      this.shapeOptions.cornerRadius = radius;
      if (this.graphics) {
        this.createDisplayObject();
      }
    }
    return this;
  }

  sides(count: number): this {
    if (this.shapeType === 'polygon' || this.shapeType === 'star') {
      this.shapeOptions.sides = count;
      if (this.graphics) {
        this.createDisplayObject();
      }
    }
    return this;
  }

  starRadii(inner: number, outer: number): this {
    if (this.shapeType === 'star') {
      this.shapeOptions.innerRadius = inner;
      this.shapeOptions.outerRadius = outer;
      if (this.graphics) {
        this.createDisplayObject();
      }
    }
    return this;
  }

  // Animation methods
  async morphTo(targetType: ShapeType, duration: number = 1000): Promise<void> {
    // This would require more complex implementation with PIXI's mesh deformation
    // For now, we'll do a simple fade transition
    if (!this.graphics) return;

    const startAlpha = this.graphics.alpha;
    const startTime = performance.now();

    // Fade out current shape
    await new Promise<void>((resolve) => {
      const fadeOut = () => {
        const elapsed = performance.now() - startTime;
        const progress = Math.min(elapsed / (duration / 2), 1);

        if (this.graphics) {
          this.graphics.alpha = startAlpha * (1 - progress);
        }

        if (progress < 1) {
          requestAnimationFrame(fadeOut);
        } else {
          resolve();
        }
      };
      fadeOut();
    });

    // Change shape type
    this.shapeType = targetType;
    await this.createDisplayObject();

    // Fade in new shape
    if (this.graphics) {
      this.graphics.alpha = 0;
      const fadeInStartTime = performance.now();

      await new Promise<void>((resolve) => {
        const fadeIn = () => {
          const elapsed = performance.now() - fadeInStartTime;
          const progress = Math.min(elapsed / (duration / 2), 1);

          if (this.graphics) {
            this.graphics.alpha = startAlpha * progress;
          }

          if (progress < 1) {
            requestAnimationFrame(fadeIn);
          } else {
            resolve();
          }
        };
        fadeIn();
      });
    }
  }

  async pulse(scale: number = 1.2, duration: number = 500): Promise<void> {
    if (!this.graphics) return;

    const originalScale = this.graphics.scale.x;
    const startTime = performance.now();

    return new Promise((resolve) => {
      const animate = () => {
        const elapsed = performance.now() - startTime;
        const progress = elapsed / duration;

        if (this.graphics) {
          // Use sine wave for smooth pulse
          const scaleValue = originalScale + 
            (scale - originalScale) * Math.sin(progress * Math.PI);
          this.graphics.scale.set(scaleValue);
        }

        if (progress < 1) {
          requestAnimationFrame(animate);
        } else {
          if (this.graphics) {
            this.graphics.scale.set(originalScale);
          }
          resolve();
        }
      };
      animate();
    });
  }

  serialize(): Record<string, unknown> {
    return {
      type: 'ShapeStimulusPixi',
      id: this.id,
      shapeType: this.shapeType,
      options: this.shapeOptions,
    };
  }
}

// Factory functions for common shapes
export function rectangle(id: string, width: number, height: number): ShapeStimulusPixi {
  return new ShapeStimulusPixi(id, 'rectangle', {
    size: { width, height },
  });
}

export function square(id: string, size: number): ShapeStimulusPixi {
  return new ShapeStimulusPixi(id, 'rectangle', {
    size: { width: size, height: size },
  });
}

export function circle(id: string, radius: number): ShapeStimulusPixi {
  return new ShapeStimulusPixi(id, 'circle', {
    size: { width: radius * 2, height: radius * 2 },
  });
}

export function ellipse(id: string, width: number, height: number): ShapeStimulusPixi {
  return new ShapeStimulusPixi(id, 'ellipse', {
    size: { width, height },
  });
}

export function polygon(id: string, sides: number, radius: number): ShapeStimulusPixi {
  return new ShapeStimulusPixi(id, 'polygon', {
    size: { width: radius * 2, height: radius * 2 },
    sides,
  });
}

export function star(id: string, points: number, innerRadius: number, outerRadius: number): ShapeStimulusPixi {
  return new ShapeStimulusPixi(id, 'star', {
    sides: points,
    innerRadius,
    outerRadius,
  });
}

