import { Event, type EventOptions } from '../core/Event.js';
import type { TimelineContext } from '../core/Timeline.js';
import { timestampToNumber, timestampDiff } from '../utils/timing.js';

export class WaitEvent extends Event {
  private waitDuration: number;

  constructor(id: string, duration: number, options?: EventOptions) {
    super(id, options);
    this.waitDuration = duration;
  }

  protected async executeEvent(context: TimelineContext): Promise<void> {
    const startTime = timestampToNumber(context.clock.now());

    return new Promise((resolve) => {
      const checkTime = () => {
        const elapsed = timestampDiff(context.clock.now(), startTime);
        if (elapsed >= this.waitDuration) {
          resolve();
        } else {
          requestAnimationFrame(checkTime);
        }
      };
      checkTime();
    });
  }

  duration(ms: number): this {
    this.waitDuration = ms;
    return this;
  }

  serialize(): Record<string, unknown> {
    return {
      type: 'WaitEvent',
      id: this.id,
      duration: this.waitDuration,
      options: this.options,
    };
  }

  static deserialize(data: Record<string, unknown>): WaitEvent {
    return new WaitEvent(
      data.id as string,
      data.duration as number,
      data.options as EventOptions
    );
  }
}

